"use client";
import React, { useState, useEffect, useCallback, useRef } from 'react';
import Link from 'next/link';
import labImagesData from '@/data/lab-images.json';

export default function LabImages() {
  const [images, setImages] = useState(labImagesData);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [zoomLevel, setZoomLevel] = useState(1);
  const [progress, setProgress] = useState(0);
  const autoPlayDelay = 5000;

  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const progressRef = useRef<NodeJS.Timeout | null>(null);

  const goToImage = useCallback((index: number) => {
    let nextIndex = index;
    if (index < 0) nextIndex = images.length - 1;
    if (index >= images.length) nextIndex = 0;
    setCurrentIndex(nextIndex);
    setProgress(0);
    setZoomLevel(1);
  }, [images.length]);

  const nextImage = useCallback(() => goToImage(currentIndex + 1), [currentIndex, goToImage]);
  const prevImage = useCallback(() => goToImage(currentIndex - 1), [currentIndex, goToImage]);

  const togglePlayPause = () => {
    setIsPlaying(!isPlaying);
  };

  const shuffleImages = () => {
    const shuffled = [...images].sort(() => Math.random() - 0.5);
    setImages(shuffled);
    setCurrentIndex(0);
    setProgress(0);
  };

  const toggleFullscreen = () => {
    setIsFullscreen(!isFullscreen);
  };

  const zoomIn = () => setZoomLevel(prev => Math.min(prev + 0.25, 3));
  const zoomOut = () => setZoomLevel(prev => Math.max(prev - 0.25, 0.5));
  const resetZoom = () => setZoomLevel(1);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowLeft') prevImage();
      if (e.key === 'ArrowRight') nextImage();
      if (e.key === ' ') {
        e.preventDefault();
        togglePlayPause();
      }
      if (e.key === 'Escape' && isFullscreen) setIsFullscreen(false);
      if (e.key === 'f' || e.key === 'F') toggleFullscreen();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isFullscreen, nextImage, prevImage, isPlaying]);

  // Autoplay and Progress
  useEffect(() => {
    if (isPlaying) {
      timerRef.current = setInterval(nextImage, autoPlayDelay);
      progressRef.current = setInterval(() => {
        setProgress(prev => {
          if (prev >= 100) return 0;
          return prev + (100 / (autoPlayDelay / 100));
        });
      }, 100);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      if (progressRef.current) clearInterval(progressRef.current);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
      if (progressRef.current) clearInterval(progressRef.current);
    };
  }, [isPlaying, nextImage]);

  return (
    <main className="container" style={{ paddingBottom: '50px' }}>
      <div className="section-title">
        <h2>Lab Photo Stream</h2>
        <p className="meta">
          Interactive gallery showcasing our lab activities. Navigate using controls or click thumbnails.
          Images auto-advance every 5 seconds.
        </p>
      </div>

      <div className={`carousel ${isFullscreen ? 'fullscreen' : ''}`} id="carousel">
        <div className="main-slide" id="mainSlide">
          <img
            src={`/${images[currentIndex].src}`}
            alt={images[currentIndex].caption}
            id="mainImage"
            style={{
              transform: `scale(${zoomLevel})`,
              transformOrigin: 'center center',
              transition: 'transform 0.3s ease, opacity 0.3s ease',
            }}
            onContextMenu={(e) => e.preventDefault()}
            onDragStart={(e) => e.preventDefault()}
          />
          <div className="caption" id="mainCaption">
            {images[currentIndex].caption}
          </div>
          <div className="image-counter" id="imageCounter">
            {currentIndex + 1} / {images.length}
          </div>

          <button
            className="fullscreen-btn"
            id="fullscreenBtn"
            title="Fullscreen"
            onClick={toggleFullscreen}
          >
            <i className={`fas ${isFullscreen ? 'fa-compress' : 'fa-expand'}`}></i>
          </button>

          <div className="zoom-controls">
            <button className="zoom-btn" id="zoomInBtn" title="Zoom In" onClick={zoomIn}>
              <i className="fas fa-search-plus"></i>
            </button>
            <button className="zoom-btn" id="zoomOutBtn" title="Zoom Out" onClick={zoomOut}>
              <i className="fas fa-search-minus"></i>
            </button>
            <button className="zoom-btn" id="resetZoomBtn" title="Reset Zoom" onClick={resetZoom}>
              <i className="fas fa-sync-alt"></i>
            </button>
          </div>
        </div>

        {isFullscreen && (
          <button className="close-fullscreen" id="closeFullscreen" onClick={toggleFullscreen}>
            <i className="fas fa-times"></i>
          </button>
        )}

        <div className="controls">
          <div>
            <button className="btn" id="prevBtn" onClick={prevImage}>
              <i className="fas fa-chevron-left"></i> Previous
            </button>
            <button className="btn" id="nextBtn" onClick={nextImage}>
              Next <i className="fas fa-chevron-right"></i>
            </button>
          </div>

          <div className="progress-container">
            <div
              className="progress-bar"
              id="progressBar"
              style={{ width: `${progress}%` }}
            ></div>
          </div>

          <div>
            <button className="btn btn-accent" id="playPauseBtn" onClick={togglePlayPause}>
              <i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'}`}></i>{' '}
              {isPlaying ? 'Pause' : 'Play'}
            </button>
            <button
              className="btn btn-outline"
              id="shuffleBtn"
              title="Shuffle"
              onClick={shuffleImages}
            >
              <i className="fas fa-random"></i>
            </button>
          </div>
        </div>

        <div className="thumbnails" id="thumbnails">
          {images.map((img, index) => (
            <div
              key={index}
              className={`thumb ${index === currentIndex ? 'active' : ''}`}
              onClick={() => {
                goToImage(index);
                setIsPlaying(false);
              }}
            >
              <img
                src={`/${img.src}`}
                alt={img.caption}
                onContextMenu={(e) => e.preventDefault()}
                onDragStart={(e) => e.preventDefault()}
              />
              <div className="thumb-overlay">{index + 1}</div>
            </div>
          ))}
        </div>
      </div>

      <p style={{ textAlign: 'center', marginTop: '30px' }}>
        <Link href="/" className="btn btn-outline" style={{ textDecoration: 'none' }}>
          <i className="fas fa-arrow-left"></i> Back to Main Site
        </Link>
      </p>
    </main>
  );
}